<?php namespace App\Domains\Tourism\Http\Controllers; use Illuminate\Http\Request; use App\Domains\Tourism\Models\Package; class PackageController { public function index() { return response()->json(Package::all()); } public function store(Request $request) { $package = Package::create($request->all()); return response()->json($package, 201); } public function show(Package $package) { return response()->json($package); } public function update(Request $request, Package $package) { $package->update($request->all()); return response()->json($package); } public function destroy(Package $package) { $package->delete(); return response()->json(null, 204); } }
